exercise.solution_code:
#include <iostream>

namespace limits {
    inline constexpr int max_calls { 3 };
}

void process(int value) {
    static int call_count { 0 };
    ++call_count;
    if (call_count <= limits::max_calls) {
        std::cout << "Call " << call_count << ": value=" << value;
        if (value == call_count)
            std::cout << " [shadow warning]";
        std::cout << '\n';
    } else {
        std::cout << "Call " << call_count << ": ignored (limit reached)\n";
    }
}

int main() {
    int v1{}, v2{}, v3{}, v4{}, v5{};
    std::cin >> v1 >> v2 >> v3 >> v4 >> v5;

    process(v1);
    process(v2);
    process(v3);
    process(v4);
    process(v5);

    return 0;
}
